for folder_name in ideas_data.keys():
    folder_path = None
    for item in os.listdir(base_dir):
        if item.startswith(folder_name.split("_")[0]):
            folder_path = os.path.join(base_dir, item)
            break
            
    if folder_path:
        desc_path = os.path.join(folder_path, "описание.json")
        with open(desc_path, "w", encoding="utf-8") as f:
            json.dump(ideas_data[folder_name], f, ensure_ascii=False, indent=2)
        print(f"Сгенерирован контент: {folder_name}")

print("Батч 36-40 для Рассела Акоффа успешно завершен!")
